create or replace function FOLDERFULLTREEFORUSER(&&rootId&& bigint, &&userId&& bigint, &&treeId&& char(32)) returns table( &&Id&& bigint, &&Name&& text, &&Folder&& bigint, &&CreationAuthor&& bigint, &&CreationDate&& timestamp, &&NodeTypeUid&& uuid, &&ImageUrl&& text, &&Virtual&& smallint, &&PermissionId&& uuid, &&SortTypeId&& bigint, &&Expanded&& smallint, &&HasChild&& smallint, &&Depth&& bigint)
as $$ select d.&&Id&&, d.&&Name&&, d.&&Folder&&, d.&&CreationAuthor&&, d.&&CreationDate&&, d.&&TypeUid&& &&NodetypeUid&&, f.&&ImageUrl&&, d.&&Virtual&&, p.&&PermissionId&&, d.&&SortTypeId&&, s.&&Expanded&&, f.&&HasChildFolders&& &&HasChild&&, r.&&Depth&& from &&Sys_DmsObjectRelation&& r inner join &&Folder&& f on f.&&Id&& = r.&&Child&& inner join &&DmsObject&& d on d.&&Id&& = f.&&Id&& inner join &&DmsObjectPermission&& p on p.&&DmsObject&& = f.&&Id&& inner join &&UserSecuritySetCache&& c on c.&&SetId&& = p.&&UserSecuritySetCacheId&& left join &&sys_DmsObjectTreeNodeState&& s on s.&&TreeId&& = $3 and s.&&User&& = $2 and s.&&DmsObject&& = f.&&Id&& and s.&&Expanded&& = 1 and s.&&ParentExpanded&& = 1 where (d.&&IsDeleted&& is null or d.&&IsDeleted&& = 0) and c.&&UserId&& = $2 and r.&&Parent&& = $1 and r.&&Owner&& in ($2, 0)
$$ language sql;

create or replace function FOLDERFULLTREEFORADMIN(&&rootId&& bigint, &&userId&& bigint, &&treeId&& char(32)) returns table( &&Id&& bigint, &&Name&& text, &&Folder&& bigint, &&CreationAuthor&& bigint, &&CreationDate&& timestamp, &&NodeTypeUid&& uuid, &&ImageUrl&& text, &&Virtual&& smallint, &&SortTypeId&& bigint, &&Expanded&& smallint, &&HasChild&& smallint, &&Depth&& bigint)
as $$ select d.&&Id&&, d.&&Name&&, d.&&Folder&&, d.&&CreationAuthor&&, d.&&CreationDate&&, d.&&TypeUid&& &&NodeTypeUid&&, f.&&ImageUrl&&, d.&&Virtual&&, d.&&SortTypeId&&, s.&&Expanded&&, f.&&HasChildFolders&& &&HasChild&&, r.&&Depth&& from &&Sys_DmsObjectRelation&& r inner join &&Folder&& f on f.&&Id&& = r.&&Child&& inner join &&DmsObject&& d on d.&&Id&& = f.&&Id&& left join &&sys_DmsObjectTreeNodeState&& s on s.&&TreeId&& = $3 and s.&&User&& = $2 and s.&&DmsObject&& = f.&&Id&& and s.&&Expanded&& = 1 and s.&&ParentExpanded&& = 1 where (d.&&IsDeleted&& is null or d.&&IsDeleted&& = 0) and r.&&Parent&& = $1 and r.&&Owner&& in ($2, 0)
$$ language sql;

create or replace function GetSubDmsObjectsQuery(&&p_Folder&& bigint) returns table( &&Id&& bigint, &&NodeTypeUid&& uuid, &&FolderId&& bigint )
as $$ with recursive t_Rec as ( select dobc.&&Id&&, dobc.&&Name&& as &&Name&&, dobc.&&Folder&&, dobc.&&TypeUid&& from &&DmsObject&& dobc inner join &&Folder&& fl on dobc.&&Id&& = fl.&&Id&& where dobc.&&Id&& = $1 union all select depg.&&Id&&, depg.&&Name&& as &&Name&&, depg.&&Folder&&, depg.&&TypeUid&& from &&DmsObject&& depg inner join t_Rec on t_Rec.&&Id&& = depg.&&Folder&& ) select t_Rec.&&Id&& as &&Id&&, t_Rec.&&TypeUid&& as &&NodeTypeUid&&, t_Rec.&&Folder&& as &&FolderId&& from t_Rec
$$ language sql;

create or replace function UpdateInheritDmsPerms(&&ObjId&& bigint, &&OnlyChildren&& integer) returns void
as $$ declare v_UserMask bigint = 72057594037927936; v_TableRecord record;
begin
for v_TableRecord in select * from UpdateDmsObjectPermsRec($1) where $2 = 0 or &&Currentid&& <> $1 loop begin
if (v_TableRecord.&&ParentId&& is not null) then begin delete from &&DmsObjectPermission&& where &&DmsObject&& = v_TableRecord.&&CurrentId&& and &&InheritedFromFolder&& is not null; insert into &&DmsObjectPermission&& (&&Id&&, &&Uid&&, &&DmsObject&&, &&Group&&, &&InheritedFromFolder&&, &&OrganizationItemEmployee&&, &&OrganizationItemPosition&&, &&PermissionId&&, &&PermissionRole&&, &&User&&, &&UserSecuritySetCacheId&& ) select (nextval('G_DmsObjectPermission')) as &&Id&&, '00000000-0000-0000-0000-000000000000', v_TableRecord.&&CurrentId&&, pdp.&&Group&&, (case when pdp.&&InheritedFromFolder&& is null then v_TableRecord.&&ParentId&& else pdp.&&InheritedFromFolder&& end) as &&InheritedFromFolder&&, pdp.&&OrganizationItemEmployee&&, pdp.&&OrganizationItemPosition&&, pdp.&&PermissionId&&, pdp.&&PermissionRole&&, (case when pdp.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then v_TableRecord.&&CreationAuthor&& else pdp.&&User&& end) as &&User&&, (case when pdp.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then (v_TableRecord.&&CreationAuthor&& | v_UserMask) else pdp.&&UserSecuritySetCacheId&& end) as &&UserSecuritySetCacheId&& from &&DmsObjectPermission&& pdp where pdp.&&DmsObject&& = v_TableRecord.&&ParentId&&; end; end if;
end; end loop; end
$$ language plpgsql;


create or replace function UpdateInheritDmsPermsPatch(ObjId bigint, PermsStr text)
returns void

as
$$
declare 
v_AddPatch int = 0;
v_RemPatch int = 1;
v_UserMask bigint = 72057594037927936;

v_Separator int;
v_ItemStr text;
v_PermissionId uuid;
v_UserId bigint;
v_GroupId bigint;
v_OrgItemPos bigint;
v_OrgItemEmp bigint;
v_SetCacheId bigint;
v_PermissionRole uuid;
v_InheritedFromFolder bigint;
v_PatchType int;
v_TableRecord record;
v_PatchTableRecord record;
begin

  create temporary table if not exists &&DmsPermPatchesTableTemp&& (
    &&PermissionId&& uuid,
    &&UserId&& bigint,
    &&GroupId&& bigint,
    &&OrganizationItemPosition&& bigint,
    &&OrganizationItemEmployee&& bigint,
    &&UserSecuritySetCacheId&& bigint,
    &&PermissionRole&& uuid,
    &&InheritedFromFolder&& bigint,
    &&PatchType&& integer
  ) on commit delete rows;
  delete from &&DmsPermPatchesTableTemp&&;

  while (position(';' in $2) > 0)
  loop
    v_Separator = position(';' in $2);
    v_ItemStr = substring($2 from 1 for v_Separator - 1);
    PermsStr = substring($2 from v_Separator + 1);

    v_Separator = position(':' in v_ItemStr);
    if (v_Separator > 0) then
    begin
      -- permission
      v_PermissionId = cast(substring(v_ItemStr from 1 for v_Separator - 1) as uuid);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);

      -- user
      v_Separator = position(':' in v_ItemStr);
      v_UserId = cast(nullif(substring(v_ItemStr from 1 for v_Separator - 1), '') as bigint);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);   

      -- group
      v_Separator = position(':' in v_ItemStr);
      v_GroupId = cast(nullif(substring(v_ItemStr from 1 for v_Separator - 1), '') as bigint);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);

      -- org item pos
      v_Separator = position(':' in v_ItemStr);
      v_OrgItemPos = cast(nullif(substring(v_ItemStr from 1 for v_Separator - 1), '') as bigint);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);

      -- org item emp
      v_Separator = position(':' in v_ItemStr);
      v_OrgItemEmp = cast(nullif(substring(v_ItemStr from 1 for v_Separator - 1), '') as bigint);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);

      -- set cache id
      v_Separator = position(':' in v_ItemStr);
      v_SetCacheId = cast(nullif(substring(v_ItemStr from 1 for v_Separator - 1), '') as bigint);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);

      -- permission role
      v_Separator = position(':' in v_ItemStr);
      v_PermissionRole = cast(substring(v_ItemStr from 1 for v_Separator - 1) as uuid);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);

      -- inherited from folder
      v_Separator = position(':' in v_ItemStr);
      v_InheritedFromFolder = cast(nullif(substring(v_ItemStr from 1 for v_Separator - 1), '') as bigint);

      -- patch type
      v_PatchType = cast(substring(v_ItemStr from v_Separator + 1) as int);

      insert into &&DmsPermPatchesTableTemp&& values(v_PermissionId, v_UserId, v_GroupId, v_OrgItemPos, v_OrgItemEmp, v_SetCacheId, v_PermissionRole, v_InheritedFromFolder, v_PatchType);
    end;
    end if;
  end loop;

  if (exists(select * from &&DmsPermPatchesTableTemp&&)) then
  begin

    for v_TableRecord in select * from UpdateDmsObjectPermsRec($1) where Currentid <> $1 loop
    begin
      -- remove
      if (exists(select * from &&DmsPermPatchesTableTemp&& where &&PatchType&& = v_RemPatch)) then
      begin      
        delete from &&DmsObjectPermission&& p
        where p.DmsObject = v_TableRecord.&&CurrentId&& and
              exists(select 1
                     from &&DmsPermPatchesTableTemp&& t
                     where t.&&PatchType&& = v_RemPatch and
                           p.&&PermissionId&& = t.&&PermissionId&& and
                          (p.&&User&& = (case when t.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then v_TableRecord.&&CreationAuthor&& else t.&&UserId&& end) or p.&&User&& is null and t.&&UserId&& is null) and
                          (p.&&Group&& = t.&&GroupId&& or p.&&Group&& is null and t.&&GroupId&& is null) and
                          (p.&&OrganizationItemPosition&& = t.&&OrganizationItemPosition&& or p.&&OrganizationItemPosition&& is null and t.&&OrganizationItemPosition&& is null) and
                          (p.&&OrganizationItemEmployee&& = t.&&OrganizationItemEmployee&& or p.&&OrganizationItemEmployee&& is null and t.&&OrganizationItemEmployee&& is null) and
                           p.&&UserSecuritySetCacheId&& = (case when t.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then ( v_TableRecord.&&CreationAuthor&& | v_UserMask) else t.&&UserSecuritySetCacheI&&d end) and
                           p.&&PermissionRole&& = t.&&PermissionRole&& and
                           p.&&InheritedFromFolder&& = case when t.&&InheritedFromFolder&& is null then $1 else t.&&InheritedFromFolder&& end);
      end;
      end if;

      -- add
      if (exists(select * from &&DmsPermPatchesTableTemp&& where &&PatchType&& = v_AddPatch)) then
      begin
        for v_PatchTableRecord in select 
            t.&&PermissionId&&,
	            (case when t.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then v_TableRecord.&&CreationAuthor&& else t.&&UserId&& end) as &&User&&,
	            t.&&GroupId&&,
	            t.&&OrganizationItemPosition&&,
	            t.&&OrganizationItemEmployee&&,
	            (case when t.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then ( v_TableRecord.&&CreationAuthor&& | v_UserMask) else t.&&UserSecuritySetCacheI&&d end) as &&UserSecuritySetCacheId&&,
	            t.&&PermissionRole&&,
	            case when t.&&InheritedFromFolder&& is null then $1 else t.&&InheritedFromFolder&& end
        from &&DmsPermPatchesTableTemp&& t 
        where t.&&PatchType&& = v_AddPatch loop
        begin
	           if (not exists(select p.&&DmsObject&& from &&DmsObjectPermission&& p
	               where p.&&DmsObject&& = v_TableRecord.&&CurrentId&& and
		              p.&&PermissionId&& = v_PatchTableRecord.&&PermissionId&& and
		              (p.&&User&& = v_PatchTableRecord.&&User&& or p.&&User&& is null and v_PatchTableRecord.&&User&& is null) and
		              (p.&&Group&& = v_PatchTableRecord.&&GroupId&& or p.&&Group&& is null and v_PatchTableRecord.&&GroupId&& is null) and
		              (p.&&OrganizationItemPosition&& = v_PatchTableRecord.&&OrganizationItemPosition&& or p.&&OrganizationItemPosition&& is null and v_PatchTableRecord.&&OrganizationItemPosition&& is null) and
		              (p.&&OrganizationItemEmployee&& = v_PatchTableRecord.&&OrganizationItemEmployee&& or p.&&OrganizationItemEmployee&& is null and v_PatchTableRecord.&&OrganizationItemEmployee&& is null) and
		              p.&&UserSecuritySetCacheId&& = v_PatchTableRecord.&&UserSecuritySetCacheId&& and
		              p.&&PermissionRole&& = v_PatchTableRecord.&&PermissionRole&& and
		              (p.&&InheritedFromFolder&& = v_PatchTableRecord.&&InheritedFromFolder&& or p.&&InheritedFromFolder&& is null and v_PatchTableRecord.&&InheritedFromFolder&& is null)
	               )) then
	           begin
		              insert into DmsObjectPermission (&&Id&&, &&Uid&&, &&DmsObject&&, &&Group&&, &&InheritedFromFolder&&, &&OrganizationItemEmployee&&,
		                  &&OrganizationItemPosition&&, &&PermissionId&&, &&PermissionRole&&, &&User&&, &&UserSecuritySetCacheId&&)
		              values (nextval('G_DmsObjectPermission'),
		                  '00000000-0000-0000-0000-000000000000',
		                  v_TableRecord.&&CurrentId&&,
		                  v_PatchTableRecord.&&GroupId&&,
		                  v_PatchTableRecord.&&InheritedFromFolder&&,
		                  v_PatchTableRecord.&&OrganizationItemEmployee&&,
		                  v_PatchTableRecord.&&OrganizationItemPosition&&,
		                  v_PatchTableRecord.&&PermissionId&&,
		                  v_PatchTableRecord.&&PermissionRole&&,
		                  v_PatchTableRecord.&&User&&,
		                  v_PatchTableRecord.&&UserSecuritySetCacheId&&);
	           end;
	           end if;
        end;
        end loop;

      end;
      end if;

    end;
    end loop;

  end;
  end if;

end

$$
language plpgsql;

create or replace function GetPermissionToAdd(p_LeftObject bigint, p_RrightObject bigint)
returns table(
	&&UserId&& bigint,
	&&GroupId&& bigint,
	&&OrganizationItemPositionId&& bigint,
	&&OrganizationItemEmployeeId&& bigint
)

as
$$

declare 
v_HasPermission int;
v_ReadPermission uuid;
v_IncludeInGroup bigint;
v_HasChild bigint;
v_TableRecord record;

begin

v_ReadPermission = 'EBD6105A-AB44-404D-8B03-1D260EBB2881';

for v_TableRecord in 
	select dop.&&PermissionId&& as &&PermissionId&&
		, dop.&&User&& as &&UserId&&, dop.&&Group&& as &&GroupId&&
		, dop.&&OrganizationItemPosition&& as &&OrganizationItemPositionId&&
		, dop.&&OrganizationItemEmployee&& as &&OrganizationItemEmployeeId&&
		, dop.&&UserSecuritySetCacheId&& as &&UserSecuritySetCacheId&&
		, dop.&&PermissionRole&& as &&PermissionRole&&
	from &&DmsObjectPermission&& dop
	where dop.&&PermissionId&& = v_ReadPermission and dop.&&DmsObject&& = $1
loop
	begin

		if (v_TableRecord.&&UserId&& is not null) then
			begin
				select count(*) 
				from &&DmsObjectPermission&& p inner join &&UserSecuritySetCache&& c on p.&&UserSecuritySetCacheId&& = c.&&SetId&&
				where &&DmsObject&& = $2 and c.&&UserId&& = v_TableRecord.&&UserId&& and p.&&PermissionId&& = v_RreadPermission
				into v_HasPermission;
			end;
		else
			begin
				if (v_TableRecord.&&OrganizationItemPositionId&& is not null) then
					begin   
						select count(*) 
						from &&DmsObjectPermission&& p inner join (
							select g.&&ParentGroupId&&, om.&&OrgItemId&&
							from GetGroups() g inner join &&UserGroup_OrgItem_Map&& om on om.&&GroupId&& = g.&&ParentGroupId&&
							) mm on mm.&&ParentGroupId&& = p.&&Group&&
						where &&DmsObject&& = $2 and mm.&&OrgItemId&& = v_TableRecord.&&OrganizationItemPositionId&&
						into v_IncludeInGroup;

						select count(*) 
						from &&DmsObjectPermission&& dop 
						where dop.&&DmsObject&& = $2 and &&PermissionRole&& = v_TableRecord.&&PermissionRole&&
							and &&OrganizationItemPosition&& in (select &&OrgItemId&& from GetOrgItemChilds(v_TableRecord.&&OrganizationItemPositionId&&))
						into v_HasChild;

						v_HasPermission = v_IncludeInGroup + v_HasChild;
					end;
				else
					begin
						if (v_TableRecord.&&OrganizationItemEmployeeId&& is not null) then
							begin                
								select count(*) 
								from &&DmsObjectPermission&& p inner join (
									select g.&&ParentGroupId&&, om.&&OrgItemId &&
									from GetGroups() g inner join &&UserGroup_OrgItem_Map&& om on om.&&GroupId&& = g.&&ParentGroupId&&
									) mm on mm.&&ParentGroupId&& = p.&&Group&&
								where &&DmsObject&& = $2 and mm.&&OrgItemId&& = v_TableRecord.&&OrganizationItemEmployeeId&&
								into v_IncludeInGroup;

								select count(*) 
								from &&DmsObjectPermission&& 
								where &&DmsObject&& = $2
									and &&PermissionRole&& = v_TableRecord.&&PermissionRole&&
									and &&OrganizationItemEmployee&& in (select &&OrgItemId&& from GetOrgItemChilds(v_TableRecord.&&OrganizationItemEmployeeId&&))
								into v_HasChild;

								v_HasPermission = v_IncludeInGroup + v_HasChild;
							end;

						else
							begin
								if (v_TableRecord.&&GroupId&& is not null) then
									begin
										select count(*) 
										from &&DmsObjectPermission&& p inner join (
											select g.&&ParentGroupId&&, g.&&ChildGroupId&& from GetGroups() g
											) gg on gg.&&ChildGroupId&& = p.&&Group&&
										where &&DmsObject&& = $2 and &&PermissionRole&& = v_TableRecord.&&PermissionRole&& and gg.&&ParentGroupId&& = v_TableRecord.&&GroupId&&
										into v_HasPermission;
									end;
								end if;
							end;
						end if;
					end;
				end if;
			end;
		end if;

		if (v_HasPermission = 0) then
			begin
				&&UserId&& = v_TableRecord.&&UserId&&;
        &&GroupId&& = v_TableRecord.&&GroupId&&;
        &&OrganizationItemPositionId&& = v_TableRecord.&&OrganizationItemPositionId&&;
				&&OrganizationItemEmployeeId&& = v_TableRecord.&&OrganizationItemEmployeeId&&;

				return next;
			end;
		end if;
	end;
end loop;

end

$$
language plpgsql;

          create or replace function DmsObjectPermissionPatch(ObjId bigint, PermsStr text)
returns void

as
$$
declare 
v_AddPatch int = 0;
v_RemPatch int = 1;
v_UserMask bigint = 72057594037927936;

v_Separator int;
v_ItemStr text;
v_PermissionId uuid;
v_UserId bigint;
v_GroupId bigint;
v_OrgItemPos bigint;
v_OrgItemEmp bigint;
v_SetCacheId bigint;
v_PermissionRole uuid;
v_InheritedFromFolder bigint;
v_PatchType int;
v_TableRecord record;
v_PatchTableRecord record;
begin

  create temporary table if not exists &&DmsPermPatchesTableTemp&& (
    &&PermissionId&& uuid,
    &&UserId&& bigint,
    &&GroupId&& bigint,
    &&OrganizationItemPosition&& bigint,
    &&OrganizationItemEmployee&& bigint,
    &&UserSecuritySetCacheId&& bigint,
    &&PermissionRole&& uuid,
    &&InheritedFromFolder&& bigint,
    &&PatchType&& integer
  ) on commit delete rows;
  delete from &&DmsPermPatchesTableTemp&&;

  while (position(';' in $2) > 0)
  loop
    v_Separator = position(';' in $2);
    v_ItemStr = substring($2 from 1 for v_Separator - 1);
    PermsStr = substring($2 from v_Separator + 1);

    v_Separator = position(':' in v_ItemStr);
    if (v_Separator > 0) then
    begin
      -- permission
      v_PermissionId = cast(substring(v_ItemStr from 1 for v_Separator - 1) as uuid);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);

      -- user
      v_Separator = position(':' in v_ItemStr);
      v_UserId = cast(nullif(substring(v_ItemStr from 1 for v_Separator - 1), '') as bigint);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);   

      -- group
      v_Separator = position(':' in v_ItemStr);
      v_GroupId = cast(nullif(substring(v_ItemStr from 1 for v_Separator - 1), '') as bigint);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);

      -- org item pos
      v_Separator = position(':' in v_ItemStr);
      v_OrgItemPos = cast(nullif(substring(v_ItemStr from 1 for v_Separator - 1), '') as bigint);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);

      -- org item emp
      v_Separator = position(':' in v_ItemStr);
      v_OrgItemEmp = cast(nullif(substring(v_ItemStr from 1 for v_Separator - 1), '') as bigint);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);

      -- set cache id
      v_Separator = position(':' in v_ItemStr);
      v_SetCacheId = cast(nullif(substring(v_ItemStr from 1 for v_Separator - 1), '') as bigint);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);

      -- permission role
      v_Separator = position(':' in v_ItemStr);
      v_PermissionRole = cast(substring(v_ItemStr from 1 for v_Separator - 1) as uuid);
      v_ItemStr = substring(v_ItemStr from v_Separator + 1);

      -- inherited from folder
      v_Separator = position(':' in v_ItemStr);
      v_InheritedFromFolder = cast(nullif(substring(v_ItemStr from 1 for v_Separator - 1), '') as bigint);

      -- patch type
      v_PatchType = cast(substring(v_ItemStr from v_Separator + 1) as int);

      insert into &&DmsPermPatchesTableTemp&& values(v_PermissionId, v_UserId, v_GroupId, v_OrgItemPos, v_OrgItemEmp, v_SetCacheId, v_PermissionRole, v_InheritedFromFolder, v_PatchType);
    end;
    end if;
  end loop;

  if (exists(select * from &&DmsPermPatchesTableTemp&&)) then
  begin

    for v_TableRecord in (select &&Id&& as &&CurrentId&&, &&Folder&& as &&ParentId&&, &&CreationAuthor&& from &&DmsObject&& where Id = $1) loop
    begin
      -- remove
      if (exists(select * from &&DmsPermPatchesTableTemp&& where &&PatchType&& = v_RemPatch)) then
      begin      
        delete from &&DmsObjectPermission&& p
        where p.&&DmsObject&& = v_TableRecord.&&CurrentId&& and
              exists(select 1
                     from &&DmsPermPatchesTableTemp&& t
                     where t.&&PatchType&& = v_RemPatch and
                           p.&&PermissionId&& = t.&&PermissionId&& and
                          (p.&&User&& = (case when t.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then v_TableRecord.&&CreationAuthor&& else t.&&UserId&& end) or p.&&User&& is null and t.&&UserId&& is null) and
                          (p.&&Group&& = t.&&GroupId&& or p.&&Group&& is null and t.&&GroupId&& is null) and
                          (p.&&OrganizationItemPosition&& = t.&&OrganizationItemPosition&& or p.&&OrganizationItemPosition&& is null and t.&&OrganizationItemPosition&& is null) and
                          (p.&&OrganizationItemEmployee&& = t.&&OrganizationItemEmployee&& or p.&&OrganizationItemEmployee&& is null and t.&&OrganizationItemEmployee&& is null) and
                           p.&&UserSecuritySetCacheId&& = (case when t.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then ( v_TableRecord.&&CreationAuthor&& | v_UserMask) else t.&&UserSecuritySetCacheId&& end) and
                           p.&&PermissionRole&& = t.&&PermissionRole&& and
                           p.&&InheritedFromFolder&& = case when t.&&InheritedFromFolder&& is null then (select &&Folder&& from &&DmsObject&& where &&Id&& = $1) else t.&&InheritedFromFolder&& end);
      end;
      end if;

      -- add
      if (exists(select * from &&DmsPermPatchesTableTemp&& where &&PatchType&& = v_AddPatch)) then
      begin
        for v_PatchTableRecord in select 
            t.&&PermissionId&&,
	            (case when t.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then v_TableRecord.&&CreationAuthor&& else t.&&UserId&& end) as &&User&&,
	            t.&&GroupId&&,
	            t.&&OrganizationItemPosition&&,
	            t.&&OrganizationItemEmployee&&,
	            (case when t.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then ( v_TableRecord.&&CreationAuthor&& | v_UserMask) else t.&&UserSecuritySetCacheI&&d end) as &&UserSecuritySetCacheId&&,
	            t.&&PermissionRole&&,
	            case when t.&&InheritedFromFolder&& is null then (SELECT &&Folder&& FROM &&DmsObject&& Where &&Id&& = $1) else t.&&InheritedFromFolder&& end
        from &&DmsPermPatchesTableTemp&& t 
        where t.&&PatchType&& = v_AddPatch loop
        begin
	           if (not exists(select p.&&DmsObject&& from &&DmsObjectPermission&& p
	               where p.&&DmsObject&& = v_TableRecord.&&CurrentId&& and
		              p.&&PermissionId&& = v_PatchTableRecord.&&PermissionId&& and
		              (p.&&User&& = v_PatchTableRecord.&&User&& or p.&&User&& is null and v_PatchTableRecord.&&User&& is null) and
		              (p.&&Group&& = v_PatchTableRecord.&&GroupId&& or p.&&Group&& is null and v_PatchTableRecord.&&GroupId&& is null) and
		              (p.&&OrganizationItemPosition&& = v_PatchTableRecord.&&OrganizationItemPosition&& or p.&&OrganizationItemPosition&& is null and v_PatchTableRecord.&&OrganizationItemPosition&& is null) and
		              (p.&&OrganizationItemEmployee&& = v_PatchTableRecord.&&OrganizationItemEmployee&& or p.&&OrganizationItemEmployee&& is null and v_PatchTableRecord.&&OrganizationItemEmployee&& is null) and
